text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 smoke 테스트가 통과될 경우 금요일 15:00 KST로 설정한다.",
        "condition": "smoke 테스트 통과"
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 package config를 확인한다. contract 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "proposer": "Hara",
        "outcome": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "proposer": "Seoyeon",
        "status": "내부 stretch goal이며 최종 결정 아님"
      },
      {
        "goal": "README 설치 절차를 목요일까지 가능하면 검토한다.",
        "owner": null,
        "status": "확정 액션 아님"
      }
    ],
    "non_decisions": [
      "고객 또는 외부 파트너는 언급되지 않았다.",
      "최종 릴리스 승인 권한자는 결정되지 않았다.",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지는 결정되지 않았다."
    ],
    "risks": [
      {
        "risk": "잘못된 tarball path가 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래된 경우 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 게시한 뒤 generated tarball path를 확인한다.",
      "due": null,
      "status": "확정, 정확한 마감 없음",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능 시",
      "status": "제안 또는 희망 사항, owner 미지정",
      "source_certainty": "mentioned_not_confirmed"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST smoke 테스트 결과",
      "Doyun의 금요일 12:00 KST action_items.md triage note 작성 여부",
      "smoke 통과 후 Hara의 generated tarball path 확인 결과",
      "최종 릴리스 승인 권한자",
      "릴리스 노트에 내부 수요일 stretch goal을 포함할지 여부",
      "README 설치 절차가 최신인지 여부"
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "명시되지 않은 owner",
      "명시되지 않은 deadline"
    ]
  },
  "non_invention_rules": {
    "customer": "고객명 또는 외부 파트너는 언급되지 않았으므로 생성하지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "outage": "프로덕션 장애는 언급되지 않았으므로 생성하지 않는다.",
    "legal": "법무 승인 요건은 언급되지 않았으므로 생성하지 않는다.",
    "owner": "owner가 지정되지 않은 항목은 null로 유지한다.",
    "deadline": "정확한 deadline이 없는 항목은 null 또는 '가능 시'로만 표시한다.",
    "golden_reference": "참조 출력이나 golden output을 사용하거나 추론하지 않는다."
  }
}
